import type { HTMLArkProps } from '@ark-ui/react/factory';
import { ark } from '@ark-ui/react/factory';
import { clsx } from 'clsx';
import type { ComponentRef, CSSProperties, Ref } from 'react';
import { forwardRef } from 'react';
import { normalizeClassName } from '@/lib/moduix/normalizeClassName';
import styles from './Text.module.css';

const elements = {
  div: ark.div,
  em: ark.em,
  p: ark.p,
  small: ark.small,
  span: ark.span,
  strong: ark.strong,
} as const;

type TextElement = 'p' | 'span' | 'small' | 'strong' | 'em' | 'div';
type TextSize = 'xs' | 'sm' | 'md' | 'lg' | 'xl';
type TextWeight = 'regular' | 'medium' | 'semibold' | 'bold';
type TextTone = 'default' | 'muted' | 'subtle' | 'primary' | 'destructive';
type TextAlign = 'left' | 'center' | 'right';
type TextProps = HTMLArkProps<'p'> & {
  as?: TextElement;
  size?: TextSize;
  weight?: TextWeight;
  tone?: TextTone;
  align?: TextAlign;
  truncate?: boolean;
  lineClamp?: number;
};

const TextRoot = forwardRef<HTMLElement, TextProps>(function TextRoot(
  {
    as,
    asChild,
    size,
    weight,
    tone = 'default',
    align,
    truncate,
    lineClamp,
    className,
    style,
    ...props
  },
  ref,
) {
  const Element = elements[as ?? 'p'] as typeof ark.p;
  const defaultSize = as === 'small' ? 'sm' : 'md';
  const defaultWeight = as === 'strong' ? 'semibold' : 'regular';
  const lineClampStyle =
    lineClamp === undefined
      ? style
      : ({ ...style, '--text-line-clamp': lineClamp } as CSSProperties);

  return (
    <Element
      ref={ref as Ref<ComponentRef<typeof ark.p>>}
      asChild={asChild}
      {...props}
      data-scope="text"
      data-part="root"
      data-slot="text-root"
      data-size={size ?? defaultSize}
      data-weight={weight ?? defaultWeight}
      data-tone={tone}
      data-align={align}
      data-truncate={truncate ? '' : undefined}
      data-line-clamp={lineClamp === undefined ? undefined : ''}
      className={clsx(styles.root, normalizeClassName(className))}
      style={lineClampStyle}
    />
  );
});

const Text = Object.assign(TextRoot, {
  Root: TextRoot,
});

export { Text };

@layer ui.components {
  .root {
    margin: 0;
    font-family: var(--text-font-family, inherit);
    font-size: var(--text-font-size-md, var(--text-md));
    font-weight: var(--text-font-weight-regular, var(--weight-regular));
    line-height: var(--text-line-height-md, var(--line-height-text-md));
    letter-spacing: var(--text-letter-spacing, 0);
    color: var(--text-default-color, var(--color-foreground));
    text-align: start;
    overflow-wrap: break-word;

    &[data-size='xs'] {
      font-size: var(--text-font-size-xs, var(--text-xs));
      line-height: var(--text-line-height-xs, var(--line-height-text-xs));
    }

    &[data-size='sm'] {
      font-size: var(--text-font-size-sm, var(--text-sm));
      line-height: var(--text-line-height-sm, var(--line-height-text-sm));
    }

    &[data-size='lg'] {
      font-size: var(--text-font-size-lg, var(--text-lg));
      line-height: var(--text-line-height-lg, var(--line-height-text-lg));
    }

    &[data-size='xl'] {
      font-size: var(--text-font-size-xl, var(--text-xl));
      line-height: var(--text-line-height-xl, var(--line-height-text-xl));
    }

    &[data-weight='medium'] {
      font-weight: var(--text-font-weight-medium, var(--weight-medium));
    }

    &[data-weight='semibold'] {
      font-weight: var(--text-font-weight-semibold, var(--weight-semibold));
    }

    &[data-weight='bold'] {
      font-weight: var(--text-font-weight-bold, var(--weight-bold));
    }

    &[data-tone='muted'] {
      color: var(--text-muted-color, var(--color-muted-foreground));
    }

    &[data-tone='subtle'] {
      color: var(--text-subtle-color, var(--color-secondary-foreground));
    }

    &[data-tone='primary'] {
      color: var(--text-primary-color, var(--color-primary));
    }

    &[data-tone='destructive'] {
      color: var(--text-destructive-color, var(--color-destructive));
    }

    &[data-align='left'] {
      text-align: left;
    }

    &[data-align='center'] {
      text-align: center;
    }

    &[data-align='right'] {
      text-align: right;
    }

    &[data-truncate] {
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }

    &[data-line-clamp] {
      display: -webkit-box;
      overflow: hidden;
      white-space: normal;
      -webkit-box-orient: vertical;
      -webkit-line-clamp: var(--text-line-clamp);
    }
  }
}
